import { Component, signal, computed } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterModule, ActivatedRoute, Router } from '@angular/router';
import { FormsModule } from '@angular/forms';

export type QuestionVm = {
  id: string;
  question: string;
  type: 'multiple_choice' | 'true_false' | 'short_answer';
  options: string[];
  correctAnswer: string;
};

export type ExamVm = {
  id: string;
  title: string;
  description: string;
  duration: number;
  questionCount: number;
  totalMarks: number;
  passingMarks: number;
  subjectName: string;
  levelName: string;
};

export type ResultVm = {
  percentage: number;
  obtainedMarks: number;
  totalMarks: number;
  passed: boolean;
};

@Component({
  selector: 'app-exam-detail',
  standalone: true,
  imports: [CommonModule, RouterModule, FormsModule],
  templateUrl: './exam-detail.component.html',
  styleUrls: ['./exam-detail.component.scss']
})
export class ExamDetailComponent {
  isLoading = signal(true);
  isStarted = signal(false);
  isSubmitted = signal(false);
  timeRemaining = signal(0);
  answers = signal<{ [key: string]: string }>({});
  result = signal<ResultVm | null>(null);

  exam = signal<ExamVm | null>(null);
  questions = signal<QuestionVm[]>([]);

  private timerInterval: any;

  constructor(private route: ActivatedRoute, private router: Router) {
    const examId = this.route.snapshot.paramMap.get('id') ?? 'e1';

    this.exam.set({
      id: examId,
      title: 'Algèbre — Équations et inéquations',
      description: 'Examen sur les équations du 1er et 2ème degré',
      duration: 60,
      questionCount: 20,
      totalMarks: 100,
      passingMarks: 50,
      subjectName: 'Mathématiques',
      levelName: '2ème année'
    });

    this.questions.set([
      {
        id: 'q1',
        question: 'Résolvez l\'équation : 2x + 5 = 13',
        type: 'multiple_choice',
        options: ['x = 3', 'x = 4', 'x = 5', 'x = 6'],
        correctAnswer: 'x = 4'
      },
      {
        id: 'q2',
        question: 'L\'équation x² = 4 admet deux solutions.',
        type: 'true_false',
        options: ['Vrai', 'Faux'],
        correctAnswer: 'Vrai'
      },
      {
        id: 'q3',
        question: 'Résolvez l\'inéquation : 3x - 2 < 7',
        type: 'short_answer',
        options: [],
        correctAnswer: 'x < 3'
      },
      {
        id: 'q4',
        question: 'Factorisez : x² - 9',
        type: 'multiple_choice',
        options: ['(x-3)(x+3)', '(x-3)²', '(x+3)²', '(x-9)(x+1)'],
        correctAnswer: '(x-3)(x+3)'
      },
      {
        id: 'q5',
        question: 'Le discriminant d\'une équation du second degré est toujours positif.',
        type: 'true_false',
        options: ['Vrai', 'Faux'],
        correctAnswer: 'Faux'
      }
    ]);

    setTimeout(() => this.isLoading.set(false), 500);
  }

  startExam() {
    const exam = this.exam();
    if (exam) {
      this.isStarted.set(true);
      this.timeRemaining.set(exam.duration * 60);
      this.startTimer();
    }
  }

  startTimer() {
    this.timerInterval = setInterval(() => {
      const current = this.timeRemaining();
      if (current > 0) {
        this.timeRemaining.set(current - 1);
      } else {
        this.submitExam();
      }
    }, 1000);
  }

  submitExam() {
    clearInterval(this.timerInterval);

    const answers = this.answers();
    const questions = this.questions();
    let obtainedMarks = 0;

    questions.forEach(q => {
      if (answers[q.id] === q.correctAnswer) {
        obtainedMarks += 20;
      }
    });

    const totalMarks = questions.length * 20;
    const percentage = Math.round((obtainedMarks / totalMarks) * 100);

    this.result.set({
      percentage,
      obtainedMarks,
      totalMarks,
      passed: percentage >= 50
    });

    this.isSubmitted.set(true);
  }

  formatTime(seconds: number): string {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  }

  setAnswer(questionId: string, answer: string) {
    this.answers.update(a => ({ ...a, [questionId]: answer }));
  }
}
<div class="min-h-screen bg-[#F8F9FA] py-8">
  <div class="mx-auto w-full max-w-4xl px-4">
    <!-- Loading -->
    <div *ngIf="isLoading()" class="flex items-center justify-center py-20">
      <div class="h-12 w-12 animate-spin rounded-full border-4 border-gray-200 border-t-[#1A73E8]"></div>
    </div>

    <!-- Exam Header -->
    <div *ngIf="!isLoading() && exam()" class="mb-6 overflow-hidden rounded-xl border border-gray-200 bg-white p-6 shadow-sm">
      <h1 class="mb-4 text-2xl font-bold text-gray-900 sm:text-3xl">{{ exam()!.title }}</h1>
      <div class="grid grid-cols-2 gap-4 text-sm text-gray-600 sm:grid-cols-4">
        <div><strong>Durée:</strong> {{ exam()!.duration }} minutes</div>
        <div><strong>Questions:</strong> {{ exam()!.questionCount }}</div>
        <div><strong>Note totale:</strong> {{ exam()!.totalMarks }}</div>
        <div><strong>Passage:</strong> {{ exam()!.passingMarks }}</div>
      </div>
    </div>

    <!-- Start Exam -->
    <div *ngIf="!isLoading() && !isStarted() && !isSubmitted()" class="py-12 text-center">
      <div class="mx-auto max-w-md rounded-xl border border-gray-200 bg-white p-8 shadow-sm">
        <h2 class="mb-4 text-2xl font-bold text-gray-900">Prêt à commencer ?</h2>
        <p class="mb-6 text-gray-600">Vous avez {{ exam()?.duration || 0 }} minutes pour compléter cet examen.</p>
        <button (click)="startExam()" class="w-full rounded-xl bg-gradient-to-br from-[#1A73E8] to-[#FF6D00] py-3 text-sm font-semibold text-white">
          Commencer l'examen
        </button>
      </div>
    </div>

    <!-- Exam Questions -->
    <div *ngIf="isStarted() && !isSubmitted()">
      <!-- Timer -->
      <div class="mb-6 rounded-xl border border-gray-200 bg-white p-4 text-center shadow-sm">
        <div class="text-2xl font-bold" [class]="timeRemaining() < 300 ? 'text-red-600' : 'text-gray-900'">
          Temps restant: {{ formatTime(timeRemaining()) }}
        </div>
      </div>

      <!-- Questions -->
      <div class="space-y-6">
        <div *ngFor="let question of questions(); let i = index" class="rounded-xl border border-gray-200 bg-white p-6 shadow-sm">
          <h3 class="mb-4 text-lg font-semibold text-gray-900">
            {{ i + 1 }}. {{ question.question }}
          </h3>

          <!-- Multiple Choice -->
          <div *ngIf="question.type === 'multiple_choice'" class="space-y-3">
            <div *ngFor="let option of question.options" class="flex items-center">
              <input 
                type="radio" 
                [name]="'question-' + question.id"
                [value]="option"
                (change)="setAnswer(question.id, option)"
                class="mr-3 h-4 w-4 text-[#1A73E8]">
              <label class="text-gray-700">{{ option }}</label>
            </div>
          </div>

          <!-- True/False -->
          <div *ngIf="question.type === 'true_false'" class="space-y-3">
            <div class="flex items-center">
              <input 
                type="radio" 
                [name]="'question-' + question.id"
                value="Vrai"
                (change)="setAnswer(question.id, 'Vrai')"
                class="mr-3 h-4 w-4 text-[#1A73E8]">
              <label class="mr-6 text-gray-700">Vrai</label>
              <input 
                type="radio" 
                [name]="'question-' + question.id"
                value="Faux"
                (change)="setAnswer(question.id, 'Faux')"
                class="mr-3 h-4 w-4 text-[#1A73E8]">
              <label class="text-gray-700">Faux</label>
            </div>
          </div>

          <!-- Short Answer -->
          <div *ngIf="question.type === 'short_answer'">
            <textarea 
              (input)="setAnswer(question.id, $any($event.target).value)"
              placeholder="Tapez votre réponse ici..."
              class="w-full rounded-lg border border-gray-300 px-3 py-2 focus:border-[#1A73E8] focus:outline-none focus:ring-2 focus:ring-[#1A73E8]/20"
              rows="4"></textarea>
          </div>
        </div>
      </div>

      <!-- Submit Button -->
      <div class="mt-8 text-center">
        <button (click)="submitExam()" class="rounded-xl bg-gradient-to-br from-[#1A73E8] to-[#FF6D00] px-8 py-3 text-sm font-semibold text-white">
          Soumettre l'examen
        </button>
      </div>
    </div>

    <!-- Results -->
    <div *ngIf="isSubmitted() && result()" class="py-12 text-center">
      <div class="mx-auto max-w-md rounded-xl border border-gray-200 bg-white p-8 shadow-sm">
        <div class="mb-6">
          <div class="mb-2 text-6xl font-bold gradient-text">
            {{ result()?.percentage }}%
          </div>
          <div class="text-2xl" [class]="result()?.passed ? 'text-green-600' : 'text-red-600'">
            {{ result()?.passed ? 'REUSSI !' : 'ÉCHOUÉ' }}
          </div>
        </div>

        <div class="mb-6 grid grid-cols-2 gap-4 text-sm text-gray-600">
          <div><strong>Score:</strong> {{ result()?.obtainedMarks }}/{{ result()?.totalMarks }}</div>
          <div><strong>Pourcentage:</strong> {{ result()?.percentage }}%</div>
        </div>

        <a [routerLink]="['/exams']" class="inline-block rounded-xl bg-gradient-to-br from-[#1A73E8] to-[#FF6D00] px-6 py-2 text-sm font-semibold text-white">
          Retour aux examens
        </a>
      </div>
    </div>
  </div>
</div>
